const fs = require('fs');
const https = require('https');

async function poll() {
  const apiKey = process.env.PREMBLY_API_KEY;
  if (!apiKey) {
    console.error('PREMBLY_API_KEY is missing');
    return;
  }

  const options = {
    hostname: 'api.prembly.com',
    port: 443,
    path: '/api/v1/checker-widget/sdk/sessions/',
    method: 'GET',
    headers: {
      'x-api-key': apiKey,
      'Accept': 'application/json'
    }
  };

  const req = https.request(options, (res) => {
    let data = '';

    res.on('data', (chunk) => {
      data += chunk;
    });

    res.on('end', () => {
      try {
        const json = JSON.parse(data);
        let count = 0;

        if (json && json.data) {
          if (Array.isArray(json.data)) {
            count = json.data.length;
          } else if (json.data.data && Array.isArray(json.data.data)) {
            count = json.data.data.length;
          } else if (typeof json.data.total === 'number') {
            count = json.data.total;
          }
        } else if (Array.isArray(json)) {
          count = json.length;
        }

        fs.writeFileSync('/home/user/app/output.log', `Total sessions: ${count}\n`);
        console.log(`Successfully wrote to output.log with count ${count}`);
      } catch (e) {
        console.error('Error parsing JSON:', e);
        fs.writeFileSync('/home/user/app/output.log', `Total sessions: 0\n`);
      }
    });
  });

  req.on('error', (error) => {
    console.error('Error polling sessions:', error);
    fs.writeFileSync('/home/user/app/output.log', `Total sessions: 0\n`);
  });

  req.end();
}

poll();

